package ftcomp

import (
	"encoding/hex"
	"fmt"
	"strings"
)

const markerControlClassHex = "" +
	""

var symbolClassHex = strings.Repeat("00", 0x100) +
	strings.Repeat("01", 0x81) +
	strings.Repeat("00", 0x20) +
	strings.Repeat("01", 0x10)

const staticWeightsHex = "" +
	""

const taggedWeightsHex = "" +
	""

var (
	markerControlClass = mustDecodeTable(markerControlClassHex, 0x100)
	symbolClass        = mustDecodeTable(symbolClassHex, modelSymbolCount)
	staticWeights      = mustDecodeWeights(staticWeightsHex, modelSymbolCount)
	taggedWeights      = mustDecodeWeights(taggedWeightsHex, modelSymbolCount)
	presetDictionary   = mustDecodeBytes(presetDictionaryHex)
)

func mustDecodeTable(s string, n int) []byte {
	b := mustDecodeBytes(s)
	if len(b) < n {
		panic(fmt.Sprintf("ftcomp: table length = %d, want at least %d", len(b), n))
	}
	return b[:n]
}

func mustDecodeBytes(s string) []byte {
	b, err := hex.DecodeString(s)
	if err != nil {
		panic(err)
	}
	return b
}

func mustDecodeWeights(s string, n int) []uint16 {
	b, err := hex.DecodeString(s)
	if err != nil {
		panic(err)
	}
	if len(b) < n*2 {
		padded := make([]byte, n*2)
		copy(padded, b)
		b = padded
	}
	if len(b) > n*2 {
		b = b[:n*2]
	}
	out := make([]uint16, n)
	for i := range out {
		out[i] = uint16(b[i*2]) | uint16(b[i*2+1])<<8
	}
	return out
}
